text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "decisions": [
      {
        "topic": "공개 릴리스 일정",
        "decision": "스모크 테스트가 통과할 경우 공개 릴리스 목표 시각은 금요일 15:00 KST로 한다.",
        "source_certainty": "확정"
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs를 검토한다.",
        "source_certainty": "확정"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경한다.",
        "result": "기각",
        "source_certainty": "확정"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "note": "내부 스트레치 골일 뿐이며 공개 릴리스 확정안이 아니다.",
        "source_certainty": "확정"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차 검토",
        "note": "목요일까지 가능하면 검토하자는 의견은 있었으나 담당자와 확정 기한은 정해지지 않았다.",
        "source_certainty": "부분 확정"
      }
    ],
    "risks": [
      {
        "risk": "tarball 경로가 잘못되면 릴리스가 지연될 수 있다.",
        "source_certainty": "확정"
      },
      {
        "risk": "README 설치 절차가 최신이 아니면 릴리스 노트가 사용자에게 오해를 줄 수 있다.",
        "source_certainty": "확정"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "미결"
      },
      {
        "question": "릴리스 노트에 수요일 내부 스트레치 골을 언급해야 하는가?",
        "status": "미결"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 공유한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "확정",
      "source_certainty": "확정"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 검토한다.",
      "due": "목요일까지 가능하면",
      "status": "미확정",
      "source_certainty": "담당자 없는 제안 수준"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 스모크 테스트 결과 공유 여부와 결과 내용을 확인한다.",
      "스모크 실패 시 Doyun의 트리아지 노트 작성 여부를 확인한다.",
      "스모크 결과 공유 이후 Hara의 tarball 경로 확인 결과를 점검한다.",
      "README 설치 절차 검토의 담당자 지정 여부를 확인한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 수요일 내부 스트레치 골을 언급할지 결정한다."
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요 여부",
      "명시되지 않은 담당자",
      "명시되지 않은 기한",
      "확정되지 않은 내용을 확정 결정처럼 표현하는 서술"
    ]
  },
  "non_invention_rules": [
    "고객명, 외부 파트너, 예산, 보안, 장애, 법무 관련 사실은 회의 기록에 없는 한 추가하지 않는다.",
    "담당자가 명시되지 않은 항목에는 임의로 owner를 배정하지 않는다.",
    "기한이 명시되지 않은 항목에는 임의의 날짜나 시간을 넣지 않는다.",
    "수요일 릴리스는 내부 스트레치 골로만 기록하고 확정 일정으로 승격하지 않는다.",
    "기각된 제안은 실행 결정처럼 쓰지 않는다.",
    "오픈 질문은 답이 정해진 것처럼 쓰지 않는다."
  ]
}
